/* Explanation of classes and ids... */ /* #gbar: Outer div containing the OneGoogle bar. */ /* #guser: Outer div containing the GAIA bar. */ /* #gbs: Iframe shim behind the more box. */ /* .gbh: Div which draws the main horizontal line. */ /* .gbd: Divs which draw horizontal lines within the more box. */ /* .gb1: Class applied to all anchors on the top line. */ /* .gb4: Class applied to all regular anchors in the Gaia bar. */ /* .gbi: Class applied to all internal anchors in the Gaia bar. */ /* .gbf: Class applied to all featured anchors in the Gaia bar. */
#gbar,#guser{ font-size:13px;
padding-top:1px !important; } #gbar{
height:22px } #guser{ padding-bottom:7px !important; text-align:right } .gbh,.gbd{ border-top:1px solid #c9d7f1; /* Needs to be 1px in order for the gaia bar to be clickable in Mac IE5. */ font-size:1px } .gbh{ height:0; position:absolute; top:24px; width:100% } /* Hack to hide this CSS from IE5 Mac and 4.x browsers and earlier. */ @media all{ /* This needs to be hidden from NS 4 and IE 4, because adding a margin */ /* would change the element to display:block. */ .gb1{ /* Setting a height on .gb1 triggers hasLayout which causes IE5 to */ /* properly render the right margin. */ height:22px; margin-right:.5em; vertical-align:top } /* Mac IE5 does not handle floats well, so we don't even try to float the */ /* OneGoogle and GAIA bars on the same line. */ #gbar{ float:left } } /* Underline the top links for all frontends. The default style on some */ /* frontends is to not underline links or to underline only on hover, */ /* so we apply the underline here in order to unify the OneGoogle bar */ /* design across products. */ a.gb1,a.gb4{ text-decoration:underline !important }
